import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;
class FizzBuzzTest {
    @Test void number_1_returns1()       { assertEquals("1",    FizzBuzz.of(1)); }
    @Test void multiple3_returns_Fizz()  { assertEquals("Fizz", FizzBuzz.of(3)); }
    @Test void multiple5_returns_Buzz()  { assertEquals("Buzz", FizzBuzz.of(5)); }
}
class FizzBuzz {
    static String of(int n) {
        if (n % 15 == 0) return "FizzBuzz";
        if (n % 3  == 0) return "Fizz";
        if (n % 5  == 0) return "Buzz";
        return String.valueOf(n);
    }
}

import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;
class SimpleStack<T> {
    private final Deque<T> items = new ArrayDeque<>();
    void push(T item) { items.push(item); }
    T pop() {
        if (isEmpty()) throw new EmptyStackException();
        return items.pop();
    }
    boolean isEmpty() { return items.isEmpty(); }
}
class SimpleStackTest {
    SimpleStack<String> stack = new SimpleStack<>();
    @Test void newStack_isEmpty()               { assertTrue(stack.isEmpty()); }
    @Test void push_oneItem_notEmpty()          { stack.push("a"); assertFalse(stack.isEmpty()); }
    @Test void pop_afterPush_returnsPushedItem() { stack.push("hello"); assertEquals("hello", stack.pop()); }
    @Test void pop_emptyStack_throwsException() { assertThrows(EmptyStackException.class, () -> stack.pop()); }
}

import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;
class PasswordValidator {
    boolean isValid(String pwd) {
        if (pwd == null) return false;
        if (pwd.length() < 8) return false;
        if (!pwd.chars().anyMatch(Character::isUpperCase)) return false;
        if (!pwd.chars().anyMatch(Character::isDigit)) return false;
        return true;
    }
}
class PasswordValidatorTest {
    PasswordValidator v = new PasswordValidator();
    @Test void null_returnsFalse()           { assertFalse(v.isValid(null)); }
    @Test void tooShort_returnsFalse()       { assertFalse(v.isValid("Abc123")); }
    @Test void noUppercase_returnsFalse()    { assertFalse(v.isValid("abc12345")); }
    @Test void noDigit_returnsFalse()        { assertFalse(v.isValid("Abcdefgh")); }
    @Test void validPassword_returnsTrue()   { assertTrue(v.isValid("Secure123")); }
}

import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;
class BankAccount {
    private double balance;
    BankAccount(double balance) { this.balance = balance; }
    void withdraw(double amount) {
        if (amount < 0) throw new IllegalArgumentException("Amount must be positive");
        if (amount > balance) throw new IllegalStateException("Insufficient funds");
        balance -= amount;
    }
    double getBalance() { return balance; }
}
class BankAccountTest {
    @Test void withdraw_lessThanBalance_reducesBalance() {
        BankAccount acc = new BankAccount(1000); acc.withdraw(300);
        assertEquals(700, acc.getBalance(), 0.01);
    }
    @Test void withdraw_exactBalance_becomesZero() {
        BankAccount acc = new BankAccount(1000); acc.withdraw(1000);
        assertEquals(0, acc.getBalance(), 0.01);
    }
    @Test void withdraw_moreThanBalance_throwsIllegalState() {
        assertThrows(IllegalStateException.class, () -> new BankAccount(1000).withdraw(2000));
    }
    @Test void withdraw_negativeAmount_throwsIllegalArgument() {
        assertThrows(IllegalArgumentException.class, () -> new BankAccount(1000).withdraw(-100));
    }
}

import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;
class WordCounter {
    Map<String, Long> count(String text) {
        if (text == null || text.isBlank()) return Map.of();
        Map<String, Long> freq = new LinkedHashMap<>();
        for (String word : text.toLowerCase().split("\\s+")) {
            freq.merge(word, 1L, Long::sum);
        }
        return freq;
    }
}
class WordCounterTest {
    WordCounter counter = new WordCounter();
    @Test void singleWord_count1() {
        assertEquals(1L, counter.count("hello").get("hello"));
    }
    @Test void twoWords_bothInMap() {
        Map<String, Long> result = counter.count("hello world");
        assertEquals(1L, result.get("hello")); assertEquals(1L, result.get("world"));
    }
    @Test void repeatedWord_count2() {
        assertEquals(2L, counter.count("hello hello").get("hello"));
    }
    @Test void caseInsensitive_sameKey() {
        Map<String, Long> result = counter.count("Mouse mouse");
        assertEquals(2L, result.get("mouse"));
        assertNull(result.get("Mouse"));
    }
}

