import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;
class ShoppingCart {
    private final Map<String, Double> items = new LinkedHashMap<>();
    void addItem(String name, double price) { items.put(name, price); }
    void removeItem(String name) { items.remove(name); }
    void applyDiscount(double rate) { items.replaceAll((n, p) -> p * (1 - rate)); }
    double getTotal() { return items.values().stream().mapToDouble(Double::doubleValue).sum(); }
}
class ShoppingCartTest {
    ShoppingCart cart = new ShoppingCart();
    @Test void empty_totalIsZero()        { assertEquals(0.0, cart.getTotal(), 0.001); }
    @Test void addOne_totalIsPrice()      { cart.addItem("Mouse",799); assertEquals(799, cart.getTotal(), 0.001); }
    @Test void addTwo_totalIsSum()        { cart.addItem("Mouse",799); cart.addItem("KB",1999); assertEquals(2798, cart.getTotal(), 0.001); }
    @Test void discount10_reducesTotal()  { cart.addItem("Mouse",1000); cart.applyDiscount(0.10); assertEquals(900, cart.getTotal(), 0.001); }
    @Test void removeItem_totalReduced()  { cart.addItem("Mouse",799); cart.addItem("KB",1999); cart.removeItem("Mouse"); assertEquals(1999, cart.getTotal(), 0.001); }
}

