import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;
class OrderPricer {
    double calculateTotal(int qty, double unitPrice, boolean premium) {
        if (qty < 0) throw new IllegalArgumentException("Qty must be non-negative");
        double base = qty * unitPrice;
        double disc = qty >= 50 ? 0.20 : qty >= 10 ? 0.10 : 0.0;
        double afterDisc = base * (1 - disc);
        return premium ? afterDisc * 0.95 : afterDisc;
    }
}
class OrderPricerTest {
    OrderPricer p = new OrderPricer();
    @Test void singleItem_noDiscount()       { assertEquals(100.0, p.calculateTotal(1,  100, false), 0.01); }
    @Test void qty10_10percentDiscount()     { assertEquals(900.0, p.calculateTotal(10, 100, false), 0.01); }
    @Test void qty50_20percentDiscount()     { assertEquals(800.0, p.calculateTotal(50, 100, false), 0.01); }
    @Test void premium_extra5percent()       { assertEquals(855.0, p.calculateTotal(10, 100, true),  0.01); }
    @Test void negativeQty_throwsIllegal()   { assertThrows(IllegalArgumentException.class, () -> p.calculateTotal(-1, 100, false)); }
}

