import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;
class RomanConverter {
    static String toRoman(int n) {
        int[]    values  = {90, 50, 40, 10,  9,  5,  4,  1};
        String[] symbols = {"XC","L","XL","X","IX","V","IV","I"};
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < values.length; i++) {
            while (n >= values[i]) { sb.append(symbols[i]); n -= values[i]; }
        }
        return sb.toString();
    }
}
class RomanConverterTest {
    @Test void one_isI()       { assertEquals("I",    RomanConverter.toRoman(1)); }
    @Test void two_isII()      { assertEquals("II",   RomanConverter.toRoman(2)); }
    @Test void four_isIV()     { assertEquals("IV",   RomanConverter.toRoman(4)); }
    @Test void five_isV()      { assertEquals("V",    RomanConverter.toRoman(5)); }
    @Test void nine_isIX()     { assertEquals("IX",   RomanConverter.toRoman(9)); }
    @Test void ten_isX()       { assertEquals("X",    RomanConverter.toRoman(10)); }
    @Test void forty_isXL()    { assertEquals("XL",   RomanConverter.toRoman(40)); }
    @Test void ninety_isXC()   { assertEquals("XC",   RomanConverter.toRoman(90)); }
    @Test void fourtyTwo_isXLII(){ assertEquals("XLII", RomanConverter.toRoman(42)); }
}

import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;
record Order(String product, int qty, double price) {}
record ProcessResult(String status, String message, double total) {}
class OrderProcessor {
    ProcessResult process(Order order) {
        if (order == null) throw new NullPointerException("Order cannot be null");
        if (order.qty() <= 0)   return new ProcessResult("REJECTED", "Qty must be positive", 0);
        if (order.price() <= 0) return new ProcessResult("REJECTED", "Price must be positive", 0);
        double total = order.qty() * order.price();
        if (order.qty() >= 10) total *= 0.90;
        return new ProcessResult("ACCEPTED", "OK", total);
    }
}
class OrderProcessorTest {
    OrderProcessor p = new OrderProcessor();
    @Test void valid_order_accepted_withTotal() {
        var r = p.process(new Order("Mouse", 2, 799));
        assertEquals("ACCEPTED", r.status()); assertEquals(1598, r.total(), 0.01);
    }
    @Test void zeroQty_rejected_correctMessage() {
        var r = p.process(new Order("Mouse", 0, 799));
        assertEquals("REJECTED", r.status()); assertTrue(r.message().contains("Qty"));
    }
    @Test void zeroPrice_rejected() {
        assertEquals("REJECTED", p.process(new Order("Mouse", 1, 0)).status());
    }
    @Test void qty10_accepted_withBulkDiscount() {
        var r = p.process(new Order("Mouse", 10, 100));
        assertEquals("ACCEPTED", r.status()); assertEquals(900, r.total(), 0.01);
    }
    @Test void nullOrder_throwsNPE() {
        assertThrows(NullPointerException.class, () -> p.process(null));
    }
}

import org.junit.jupiter.api.*;
import java.util.*;
import java.util.stream.*;
import static org.junit.jupiter.api.Assertions.*;
class InsufficientStockException extends RuntimeException { InsufficientStockException(String m) { super(m); } }
class InventoryManager {
    private final Map<String, Integer> stock = new LinkedHashMap<>();
    private final Map<String, Integer> minimums = new HashMap<>();
    int getStock(String product) { return stock.getOrDefault(product, 0); }
    void addStock(String product, int qty) { stock.merge(product, qty, Integer::sum); }
    void removeStock(String product, int qty) {
        int current = getStock(product);
        if (qty > current) throw new InsufficientStockException(
            "Requested " + qty + " but only " + current + " available");
        stock.put(product, current - qty);
    }
    List<String> getProducts() {
        return stock.entrySet().stream().filter(e -> e.getValue() > 0)
            .map(Map.Entry::getKey).collect(Collectors.toList());
    }
    void setMinimum(String product, int minimum) { minimums.put(product, minimum); }
    boolean isLow(String product) {
        int min = minimums.getOrDefault(product, 0);
        return getStock(product) < min;
    }
    void transferStock(String from, String to, int qty) {
        removeStock(from, qty);
        addStock(to, qty);
    }
}
class InventoryManagerTest {
    InventoryManager inv = new InventoryManager();
    @Test void empty_stockIsZero()             { assertEquals(0, inv.getStock("P001")); }
    @Test void addStock_returnsQty()           { inv.addStock("P001", 50); assertEquals(50, inv.getStock("P001")); }
    @Test void addTwice_cumulative()           { inv.addStock("P001", 50); inv.addStock("P001", 20); assertEquals(70, inv.getStock("P001")); }
    @Test void removeStock_reduces()           { inv.addStock("P001", 50); inv.removeStock("P001", 10); assertEquals(40, inv.getStock("P001")); }
    @Test void removeMoreThanAvailable_throws(){ inv.addStock("P001", 10);
        assertThrows(InsufficientStockException.class, () -> inv.removeStock("P001", 20)); }
    @Test void getProducts_onlyWithStock()     { inv.addStock("P001", 50); inv.addStock("P002", 0);
        assertTrue(inv.getProducts().contains("P001")); assertFalse(inv.getProducts().contains("P002")); }
    @Test void isLow_belowMinimum_true()       { inv.addStock("P001", 5); inv.setMinimum("P001", 10); assertTrue(inv.isLow("P001")); }
    @Test void transferStock_movesQty()        { inv.addStock("P001", 50); inv.addStock("P002", 20);
        inv.transferStock("P001", "P002", 10);
        assertEquals(40, inv.getStock("P001")); assertEquals(30, inv.getStock("P002")); }
}
